inline bool haritaCarpismaKontrolu(float x, float y, float genislik, float yukseklik) {
    int solGrid = static_cast<int>(x / tileSize);
    int sagGrid = static_cast<int>((x + genislik) / tileSize);
    int ustGrid = static_cast<int>(y / tileSize);
    int altGrid = static_cast<int>((y + yukseklik) / tileSize);

    if (solGrid < 0 || sagGrid >= MAP_WIDTH || ustGrid < 0 || altGrid >= MAP_HEIGHT) return true;

    for (int gy = ustGrid; gy <= altGrid; ++gy) {
        for (int gx = solGrid; gx <= sagGrid; ++gx) {
            int tile = harita[gy][gx];
            if (tile == 1 || tile == 2 || tile == 3) { return true; }
        }
    }
    return false;
}
